def _pick_col(df, candidates):
    cmap = {str(c).lower(): c for c in df.columns}
    for cand in candidates:
        if cand.lower() in cmap:
            return cmap[cand.lower()]
    for c in df.columns:
        lc = str(c).lower()
        if any(cand.lower() in lc for cand in candidates):
