    if not np.isfinite(ap_company2495_to_station98_distance_km) or not np.isfinite(ap_company2495_to_station98_bearing_deg):
        lon_cands = ["company_lon","company_longitude","company_lng","source_lon","source_longitude","lon_company","longitude_company"]
